<template>
	<view class="body">
		<scroll-view scroll-y class="scroll_content" :style="{
		height:'calc(100% - 1px - '+sys.top+'px)',
			marginTop: sys.top + 'px',
		}">

			<view class="list">
				<view class="item" v-for="(item,index) in order.cards" :key="index">
					<view class="no">
						{{index+1}}
					</view>
					<view class="img">
						<uqrcode :ref="'uqrcode'+index" :h5SaveIsDownload="false" :canvas-id="'qrcode'+index"
							:value=" order.weidianpro_btn && order.recharge_url && !item.card_no && item.card_password ? order.recharge_url + item.card_password :item.card_no + item.card_password" size="300" @click="savePosterPath(index)"
							@complete="create_success($event,index)">
							<template v-slot:h5save="{ tempFilePath }">
								<view
									style="display: flex;flex-direction: column;align-items: center;width: 700rpx;padding: 30px 0;background-color: #ffffff;">
									<text style="font-size: 14px;color: #9a9b9c;">若保存失败，请长按二维码进行保存</text>
									<image style="width: 500rpx;height: 500rpx;margin-top: 20px;" :src="tempFilePath">
									</image>
								</view>
							</template>
						</uqrcode>
					</view>
					<view class="pass">
						{{item.card_no + item.card_password}}
					</view>
				</view>
			</view>
			<view class="safeAreaBottom"></view>
		</scroll-view>
	</view>
</template>

<script>
	export default {
		data() {
			return {
				sys: this.$util.sys(),
				order: {
					cards: [],
					ordersn: '',
				},
				imgList: [

				]


			};
		},
		onLoad(e) {

			//从缓存中获取
			uni.getStorage({
				key: 'order_info_data',
				success: (res) => {
					let data = JSON.parse(res.data)

					this.order = data
					// this.loadData()
				},
				fail: (e) => {
					this.$util.back()
				}
			});

		},

		methods: {
			previewImage(url) { // index 索引 如果 需要复用方法 可以使用 类型来进行区分(val)

				uni.previewImage({
					current: 0, // 当前显示图片的索引值
					urls: [url], // 需要预览的图片列表，photoList要求必须是数组

				})
			},
			create_success(e, index) {


				this.$refs['uqrcode' + index][0].toTempFilePath({
					success: res => {

						this.imgList[index] = res.tempFilePath

					}
				});

			},
			async loadData() {
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})

				uni.hideLoading()
			},
			savePosterPath(index) {


				// uni.previewImage({
				// 	current: index, // 当前显示图片的索引值
				// 	urls: this.imgList, // 需要预览的图片列表，photoList要求必须是数组	
				// })




				this.$refs['uqrcode' + index][0].toTempFilePath({
					success: res => {

						uni.previewImage({
							current: 0, // 当前显示图片的索引值
							urls: [res.tempFilePath], // 需要预览的图片列表，photoList要求必须是数组

						})
					}
				});



			}

		}
	}
</script>
<style scoped>
	page {
		background-color: #f4f5f8;
		width: 100%;
		height: 100%;

	}
</style>
<style lang="scss" scoped scoped>
	.body {
		width: 100%;
		height: 100%;
	}

	.list {
		display: flex;
		padding: 20rpx;
		flex-direction: column;
		align-items: center;
		gap:20rpx;
	}

	.list .item {
		gap:20rpx;
		display: flex;
		flex-direction: column;
		align-items: center;
		border-radius: 20rpx;
		width: 98%;
		background-color: #fff;
		justify-content: space-around;
		// height: 600rpx;
		.pass{
			padding: 20rpx;
		}
	}
</style>